<?php namespace App\Repositories\Fee;use App\Repositories\BaseRepository;use App\Models\Fee\FeeCategory;use Illuminate\Database\Eloquent\Collection;class FeeCategoryRepository extends BaseRepository{    public function __construct(FeeCategory $model)    {        $this->model = $model;        parent::__construct($model);    }    public function findByCode(string $code): ?FeeCategory    {        return $this->query()->where('code', $code)->first();    }    public function findByName(string $name): ?FeeCategory    {        return $this->query()->where('name', $name)->first();    }    public function getActiveCategories(): Collection    {        return $this->query()->where('is_active', true)->get();    }    public function getByFrequency(string $frequency): Collection    {        return $this->findByField('frequency', $frequency);    }    public function searchCategories(string $keyword): Collection    {        return $this->query()->where('name', 'like', "%{$keyword}%")->orWhere('code', 'like', "%{$keyword}%")->orWhere('description', 'like', "%{$keyword}%")->get();    }}